```

```tsx
// components/Button.tsx — works as Server Component
import styles from './Button.module.css';

type ButtonProps = {
  variant?: 'primary' | 'secondary';
  size?: 'default' | 'large';
  children: React.ReactNode;
} & React.ButtonHTMLAttributes<HTMLButtonElement>;

export function Button({ variant = 'primary', size = 'default', children, ...props }: ButtonProps) {
  const className = [
    styles.button,
    styles[variant],
    size === 'large' && styles.large,
  ].filter(Boolean).join(' ');

  return <button className={className} {...props}>{children}</button>;
}
```

CSS Modules generate unique class names like `Button_primary__a1b2c` at build time, preventing collisions. Use `composes` for style inheritance within modules. For global styles, use `:global(.className)` or a regular `.css` file.

`useTransition` marks state updates as non-urgent, allowing React to keep the UI responsive during expensive re-renders. In React 19, transitions can also be async (e.g., server actions).

```tsx
import { useState, useTransition } from 'react';

function SearchPage() {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<string[]>([]);
  const [isPending, startTransition] = useTransition();

  function handleSearch(value: string) {
    setQuery(value); // Urgent: update input immediately

    startTransition(async () => {
      // Non-urgent: can be interrupted
      const data = await fetch(`/api/search?q=${value}`).then(r => r.json());
      setResults(data);
    });
  }

  return (
    <div>
      <input value={query} onChange={(e) => handleSearch(e.target.value)} />
      {isPending && <div className="spinner" />}
      <ul>
        {results.map((r) => <li key={r}>{r}</li>)}
      </ul>
    </div>
  );
}

// React 19: transitions with server actions
function SubmitButton() {
  const [isPending, startTransition] = useTransition();

  return (
    <button
      disabled={isPending}
      onClick={() => startTransition(async () => {
        await saveToDatabase(); // server action
      })}
    >
      {isPending ? 'Saving...' : 'Save'}
    </button>
  );
}
```

Transitions are interruptible — if the user types again before the results arrive, React abandons the stale render. `isPending` is true from the moment `startTransition` is called until all updates inside it complete, including async ones in React 19.

Suspense lets you declare loading states declaratively. When a child component suspends (throws a Promise), Suspense shows the fallback until the Promise resolves.

```tsx
import { Suspense } from 'react';

// Nested Suspense boundaries for granular loading states
export default function Dashboard() {
  return (
    <div className="grid grid-cols-2 gap-4">
      <Suspense fallback={<Skeleton className="h-64" />}>
        <RevenueChart />
      </Suspense>
      <Suspense fallback={<Skeleton className="h-64" />}>
        <UserStats />
      </Suspense>
      <Suspense fallback={<TableSkeleton rows={5} />}>
        <RecentOrders />
      </Suspense>
    </div>
  );
}

// Server Component that fetches data (Next.js App Router)
async function RevenueChart() {
  const data = await getRevenueData(); // async fetch suspends
  return <Chart data={data} />;
}

// Grouping with single boundary
// Both load together, single loading state
<Suspense fallback={<FullPageSpinner />}>
  <Header />
  <MainContent />
  <Sidebar />
</Suspense>

// Sequential (waterfall) — inner waits for outer
<Suspense fallback={<Skeleton />}>
  <UserProfile userId={id} />
  <Suspense fallback={<PostsSkeleton />}>
    <UserPosts userId={id} />  {/* starts after UserProfile resolves */}
  </Suspense>
</Suspense>
```

Place Suspense boundaries around independent data needs — each boundary creates a separate loading state. Avoid wrapping every component; instead, identify natural loading groups. In Next.js, create `loading.tsx` files which automatically become Suspense boundaries for that route segment.

Streaming SSR sends HTML progressively as components resolve, instead of waiting for all data before sending any HTML. Next.js App Router supports this out of the box with Suspense.

```tsx
// app/dashboard/page.tsx
import { Suspense } from 'react';

export default function DashboardPage() {
  return (
    <main>
      {/* Sent immediately — no data dependency */}
      <h1>Dashboard</h1>
      <nav>...</nav>

      {/* Streamed in when data resolves */}
      <Suspense fallback={<p>Loading stats...</p>}>
        <SlowStats />
      </Suspense>

      <Suspense fallback={<p>Loading feed...</p>}>
        <SlowerFeed />
      </Suspense>
    </main>
  );
}

async function SlowStats() {
  const stats = await fetch('https://api.example.com/stats', {
    next: { revalidate: 60 },
  }).then(r => r.json());
  return (
    <div className="grid grid-cols-3 gap-4">
      <StatCard label="Revenue" value={stats.revenue} />
      <StatCard label="Users" value={stats.users} />
      <StatCard label="Orders" value={stats.orders} />
    </div>
  );
}

// app/dashboard/loading.tsx — route-level Suspense boundary
export default function Loading() {
  return <DashboardSkeleton />;
}
```

The browser receives the shell HTML immediately (navigation, header, skeleton fallbacks), then each Suspense boundary is replaced with real content as its data arrives. This dramatically improves Time to First Byte (TTFB) and First Contentful Paint (FCP). The `loading.tsx` file acts as an automatic Suspense boundary for the entire route segment — it wraps the `page.tsx` content.

When the server-rendered HTML does not match the client-side render, React throws a hydration error. This is one of the most common Next.js errors.

```
Error: Hydration failed because the initial UI does not match what was rendered on the server.

Warning: Expected server HTML to contain a matching <div> in <p>.
```

**Common causes and fixes:**

```tsx
// 1. WRONG — Date/time differs between server and client
export default function Page() {
  return <p>{new Date().toLocaleString()}</p>; // Different on server vs client
}

// FIX — use useEffect for client-only values
export default function Page() {
  const [time, setTime] = useState<string | null>(null);
  useEffect(() => setTime(new Date().toLocaleString()), []);
  return <p>{time ?? 'Loading...'}</p>;
}

// 2. WRONG — invalid HTML nesting
<p><div>nested</div></p>  // <div> inside <p> is invalid HTML

// 3. WRONG — browser extensions inject elements
// FIX: Use suppressHydrationWarning on the html/body tag
<body suppressHydrationWarning>{children}</body>

// 4. WRONG — conditional rendering based on window/localStorage
export default function Nav() {
  const isLoggedIn = typeof window !== 'undefined' && localStorage.getItem('token');
  return isLoggedIn ? <UserMenu /> : <LoginButton />;
}

// FIX — defer to useEffect
const [isLoggedIn, setIsLoggedIn] = useState(false);
useEffect(() => {
  setIsLoggedIn(!!localStorage.getItem('token'));
}, []);
```

Use `suppressHydrationWarning` sparingly — only on elements with intentionally different content (timestamps, browser-extension targets). For `typeof window` checks, always use `useEffect` to synchronize after hydration.

This error occurs when you use React hooks (`useState`, `useEffect`, `useContext`, etc.) in a file that is not marked as a Client Component.

```
Error: You're importing a component that needs useState. It only works in a Client Component
but none of its parents are marked with "use client", so they're Server Components by default.

   ╭─[/app/components/Counter.tsx:1:1]
 1 │ import { useState } from 'react';
   ·          ────────
```

**Fix:** Add `'use client'` directive at the top of the file:

```tsx
'use client'; // Must be the very first line (before imports)

import { useState } from 'react';

export function Counter() {
  const [count, setCount] = useState(0);
  return <button onClick={() => setCount(c => c + 1)}>{count}</button>;
}
```

**Strategy for minimizing Client Components:**

```tsx
// app/blog/[slug]/page.tsx — Server Component (default)
import { LikeButton } from './LikeButton'; // client component

export default async function BlogPost({ params }: { params: Promise<{ slug: string }> }) {
  const { slug } = await params;
  const post = await getPost(slug); // server-side data fetch
  return (
    <article>
      <h1>{post.title}</h1>
      <div>{post.content}</div>
      <LikeButton postId={post.id} /> {/* only interactive part is client */}
    </article>
  );
}
```

Push `'use client'` to the leaf components that actually need interactivity. Server Components can import Client Components, but NOT the reverse. Props passed from Server to Client Components must be serializable (no functions, classes, or Dates).

The Edge Runtime used by Next.js middleware restricts dynamic code evaluation. Libraries that use `eval`, `new Function()`, or certain Node.js APIs will fail.

```
Error: Dynamic Code Evaluation (e.g., 'eval', 'new Function', 'WebAssembly.compile')
not allowed in Edge Runtime.
Learn more: https://nextjs.org/docs/messages/edge-dynamic-code-evaluation
```

**Common triggers:**
- `jsonwebtoken` (uses `eval`) — use `jose` instead
- `bcrypt` (native module) — use `bcryptjs` or verify passwords in API routes
- `Handlebars`, `lodash.template` — use string interpolation

```typescript
// middleware.ts — WRONG
import jwt from 'jsonwebtoken';
const decoded = jwt.verify(token, secret); // Uses eval internally

// middleware.ts — CORRECT
import { jwtVerify } from 'jose';

export async function middleware(request: NextRequest) {
  const token = request.cookies.get('token')?.value;
  if (!token) return NextResponse.redirect(new URL('/login', request.url));

  try {
    const secret = new TextEncoder().encode(process.env.JWT_SECRET!);
    const { payload } = await jwtVerify(token, secret);
    const response = NextResponse.next();
    response.headers.set('x-user-id', payload.sub as string);
    return response;
  } catch {
    return NextResponse.redirect(new URL('/login', request.url));
  }
}
```

The Edge Runtime only supports Web APIs (fetch, crypto, TextEncoder, etc.). If you need Node.js APIs, move the logic to an API route (`export const runtime = 'nodejs'`) and call it from middleware, or do the check in a Server Component.

A reusable hook that tracks CSS media query matches. It handles SSR by defaulting to a provided value and updating after hydration.

```typescript
import { useState, useEffect, useCallback } from 'react';

function useMediaQuery(query: string, defaultValue = false): boolean {
  const getMatches = useCallback((): boolean => {
    if (typeof window === 'undefined') return defaultValue;
    return window.matchMedia(query).matches;
  }, [query, defaultValue]);

  const [matches, setMatches] = useState(getMatches);

  useEffect(() => {
    const mql = window.matchMedia(query);
    setMatches(mql.matches);

    const handler = (e: MediaQueryListEvent) => setMatches(e.matches);
    mql.addEventListener('change', handler);
    return () => mql.removeEventListener('change', handler);
  }, [query]);

  return matches;
}

// Usage
function Sidebar() {
  const isMobile = useMediaQuery('(max-width: 768px)');
  const prefersReducedMotion = useMediaQuery('(prefers-reduced-motion: reduce)');
  const isDarkMode = useMediaQuery('(prefers-color-scheme: dark)');

  if (isMobile) return <MobileDrawer animated={!prefersReducedMotion} />;
  return <DesktopSidebar />;
}

// With Tailwind breakpoint
function ResponsiveGrid() {
  const isLg = useMediaQuery('(min-width: 1024px)');
  return <div>{isLg ? <GridView /> : <ListView />}</div>;
}
```

Avoid flash of wrong content by choosing the right `defaultValue` for your use case (e.g., default to mobile for mobile-first designs). For SSR, the initial render uses `defaultValue` and updates after `useEffect` runs on the client.

Debouncing prevents expensive operations (API calls, filtering large lists) from firing on every keystroke. This hook delays updating the debounced value until the user stops typing.

```typescript
import { useState, useEffect } from 'react';

function useDebouncedValue<T>(value: T, delay: number): T {
  const [debouncedValue, setDebouncedValue] = useState(value);

  useEffect(() => {
    const timer = setTimeout(() => setDebouncedValue(value), delay);
    return () => clearTimeout(timer);
  }, [value, delay]);

  return debouncedValue;
}

// Usage: search with API call
function SearchPage() {
  const [query, setQuery] = useState('');
  const debouncedQuery = useDebouncedValue(query, 300);

  const { data, isLoading } = useSWR(
    debouncedQuery ? `/api/search?q=${debouncedQuery}` : null,
    fetcher
  );

  return (
    <div>
      <input
        value={query}
        onChange={(e) => setQuery(e.target.value)}
        placeholder="Search..."
      />
      {isLoading && <Spinner />}
      {data?.map((item: { id: string; title: string }) => (
        <div key={item.id}>{item.title}</div>
      ))}
    </div>
  );
}
```

The input updates immediately (responsive typing), but the API call only fires 300ms after the user stops typing. When `query` changes, the old timeout is cleared and a new one is set. Pair with `useSWR` or `useQuery` which handle deduplication and caching of the actual requests.

Choosing a state management approach depends on the complexity, re-render sensitivity, and scope of your shared state.

```typescript
// 1. React Context — built-in, good for low-frequency updates
const ThemeContext = createContext<'light' | 'dark'>('light');
// Problem: ALL consumers re-render on any context value change

// 2. Zustand — minimal API, selector-based re-renders
import { create } from 'zustand';

const useStore = create<{ count: number; name: string; inc: () => void }>((set) => ({
  count: 0,
  name: '',
  inc: () => set((s) => ({ count: s.count + 1 })),
}));

// Only re-renders when count changes, not name
function Counter() {
  const count = useStore((s) => s.count);
  return <span>{count}</span>;
}

// 3. Jotai — atomic model, bottom-up composition
import { atom, useAtom } from 'jotai';

const countAtom = atom(0);
const doubleAtom = atom((get) => get(countAtom) * 2); // derived

function Counter() {
  const [count, setCount] = useAtom(countAtom);
  return <button onClick={() => setCount((c) => c + 1)}>{count}</button>;
}
```

**Context**: No extra deps, good for themes/locale/auth. Bad for frequent updates (no selectors).
**Zustand**: 1.1KB, works outside React, supports middleware (persist, devtools, immer). Best for medium-large apps.
**Jotai**: 2KB, atomic model like Recoil but simpler. Best when state is naturally composed of small independent pieces. Supports async atoms natively.

All three work with Server Components — just wrap the interactive parts in `'use client'`.

A common misconception is that `useEffect` cleanup only runs on unmount. In reality, the cleanup function runs before every re-execution of the effect AND on unmount.

```tsx
import { useState, useEffect } from 'react';

function ChatRoom({ roomId }: { roomId: string }) {
  useEffect(() => {
    console.log(`Connecting to ${roomId}`);
    const conn = createConnection(roomId);
    conn.connect();

    return () => {
      // Runs BEFORE effect re-runs with new roomId
      // AND when component unmounts
      console.log(`Disconnecting from ${roomId}`);
      conn.disconnect();
    };
  }, [roomId]);

  return <div>Chat: {roomId}</div>;
}

// Timeline when roomId changes from 'general' to 'random':
// 1. "Disconnecting from general" (cleanup old effect)
// 2. "Connecting to random"       (run new effect)

// In Strict Mode (dev), React mounts → unmounts → mounts:
// 1. "Connecting to general"
// 2. "Disconnecting from general"
// 3. "Connecting to general"
// This exposes missing cleanup functions!
```

Strict Mode double-invocation is intentional — it catches bugs like:
- WebSocket connections that leak
- Event listeners not removed
- Timers not cleared
- Subscriptions that accumulate

If your component behaves differently after the double-mount, your cleanup is incomplete. Fix the cleanup rather than disabling Strict Mode.

React 19's `useOptimistic` hook lets you show an optimistic state while an async action (like a server mutation) is in progress. The UI updates instantly and rolls back if the action fails.

```tsx
import { useOptimistic, useTransition } from 'react';

type Message = { id: string; text: string; sending?: boolean };

function Chat({ messages, sendMessage }: {
  messages: Message[];
  sendMessage: (text: string) => Promise<void>;
}) {
  const [optimisticMessages, addOptimistic] = useOptimistic(
    messages,
    (state, newMessage: string) => [
      ...state,
      { id: crypto.randomUUID(), text: newMessage, sending: true },
    ]
  );
  const [isPending, startTransition] = useTransition();

  async function handleSend(formData: FormData) {
    const text = formData.get('message') as string;
    addOptimistic(text);
    startTransition(async () => {
      await sendMessage(text); // server action
    });
  }

  return (
    <div>
      <ul>
        {optimisticMessages.map((msg) => (
          <li key={msg.id} style={{ opacity: msg.sending ? 0.6 : 1 }}>
            {msg.text}
            {msg.sending && <span> (sending...)</span>}
          </li>
        ))}
      </ul>
      <form action={handleSend}>
        <input name="message" />
        <button type="submit">Send</button>
      </form>
    </div>
  );
}
```

The optimistic state is merged with the real state. When the action completes and the parent re-renders with updated `messages`, the optimistic value is automatically replaced. If the action throws, React reverts to the last known good state.

React 19 introduces `use()` — a special hook that can read Promises and Context, and unlike other hooks, can be called inside conditionals and loops.

```tsx
import { use, Suspense } from 'react';

// Reading a Promise — integrates with Suspense
function UserProfile({ userPromise }: { userPromise: Promise<User> }) {
  const user = use(userPromise); // suspends until resolved
  return <h1>{user.name}</h1>;
}

// Called conditionally — unlike useContext!
function ThemeText({ showTheme }: { showTheme: boolean }) {
  if (showTheme) {
    const theme = use(ThemeContext); // valid inside a conditional!
    return <p>Current theme: {theme}</p>;
  }
  return <p>Theme hidden</p>;
}

// Parent passes the promise (created outside render)
function Page({ id }: { id: string }) {
  // Create promise once, pass as prop
  const userPromise = fetchUser(id);

  return (
    <Suspense fallback={<Spinner />}>
      <UserProfile userPromise={userPromise} />
    </Suspense>
  );
}

// WRONG — do not create promise inside render without caching
function Bad() {
  const data = use(fetch('/api/data').then(r => r.json())); // new promise every render!
}
```

Key rules: The promise must be created outside the component or cached (e.g., via a framework or React cache). Creating a new promise inside render causes an infinite suspend loop. `use()` replaces the `throw promise` pattern and works with async Server Components in frameworks like Next.js.

This error occurs when a state update is triggered synchronously during another component's render phase. React enforces unidirectional data flow — rendering should be pure.

```
Warning: Cannot update a component (`Parent`) while rendering
a different component (`Child`). To locate the bad setState() call inside `Child`,
follow the stack trace.
```

```tsx
// WRONG — setState during render
function Child({ onCount }: { onCount: (n: number) => void }) {
  const items = useItems();
  onCount(items.length); // Calls parent setState during render!
  return <ul>{items.map(i => <li key={i.id}>{i.name}</li>)}</ul>;
}

function Parent() {
  const [count, setCount] = useState(0);
  return (
    <div>
      <p>{count} items</p>
      <Child onCount={setCount} />
    </div>
  );
}

// FIX — move to useEffect
function Child({ onCount }: { onCount: (n: number) => void }) {
  const items = useItems();
  useEffect(() => {
    onCount(items.length);
  }, [items.length, onCount]);
  return <ul>{items.map(i => <li key={i.id}>{i.name}</li>)}</ul>;
}

// ALTERNATIVE FIX — lift state up
function Parent() {
  const items = useItems();
  return (
    <div>
      <p>{items.length} items</p>
      <ItemList items={items} />
    </div>
  );
}
```

The most common cause is calling a callback prop (which triggers parent setState) directly in the render body. Wrap such calls in `useEffect`. Better yet, restructure so the parent owns the data and passes it down.
